const t = $input.item.json;
if (!t.task_id) throw new Error('No task_id in input: ' + JSON.stringify(t));
return [{ json: {
  task_id: String(t.task_id),
  lesson_id: String(t.lesson_id),
  subject: String(t.subject),
  grade: Number(t.grade),
  lang: String(t.lang),
  pdf_uri: String(t.pdf_uri)
}}];

const task = $('Set Task').item.json;

const fs = require('fs');
let systemPrompt = 'You are a curriculum extraction assistant. Extract structured lesson content from the provided textbook PDF text.';
try { systemPrompt = fs.readFileSync('/home/node/nets/frameworks/system/extraction.md', 'utf8'); } catch(e) {}

let outputSchema = '{}';
try { outputSchema = fs.readFileSync('/home/node/nets/frameworks/schemas/lesson.json', 'utf8'); } catch(e) {}

let pdfContent = 'PDF content unavailable';
try {
  const buf = fs.readFileSync(task.pdf_uri);
  pdfContent = buf.slice(0, 60000).toString('latin1');
} catch(e) {
  pdfContent = 'Could not read PDF: ' + e.message;
}

const payload = {
  model: 'kimi-k2.5',
  messages: [
    { role: 'system', content: systemPrompt },
    { role: 'user', content: `CONTEXT: subject=${task.subject}, grade=${task.grade}, lang=${task.lang}\n\nINPUT PDF CONTENT:\n${pdfContent}\n\nTASK: Extract the FIRST THEME/CHAPTER only. Return JSON matching this schema exactly:\n${outputSchema}` }
  ],
  response_format: { type: 'json_object' },
  temperature: 1,
  max_tokens: 16000
};

return [{ json: { payload, task_id: task.task_id, lesson_id: task.lesson_id, subject: task.subject, grade: task.grade, lang: task.lang, pdf_uri: task.pdf_uri, call_start: Date.now() } }];

const response = $json;
const meta = $('Build Extraction Prompt').item.json;

let lessonJson;
try {
  lessonJson = JSON.parse(response.choices[0].message.content);
} catch(e) {
  throw new Error('Invalid JSON from extraction: ' + e.message);
}

const fs = require('fs');
try { fs.mkdirSync('/home/node/nets/nets-output', { recursive: true }); } catch(e) {}
const lessonPath = `/home/node/nets/nets-output/${meta.lesson_id}_lesson.json`;
fs.writeFileSync(lessonPath, JSON.stringify(lessonJson, null, 2));

const tokensIn = response.usage?.prompt_tokens || 0;
const tokensOut = response.usage?.completion_tokens || 0;
const costUsd = (tokensIn * 0.60 + tokensOut * 2.50) / 1000000;

return [{ json: {
  lesson_path: lessonPath,
  task_id: meta.task_id,
  lesson_id: meta.lesson_id,
  subject: meta.subject,
  grade: meta.grade,
  lang: meta.lang,
  pdf_uri: meta.pdf_uri,
  tokens_in: tokensIn,
  tokens_out: tokensOut,
  cost_usd: costUsd
}}];

const task = $('Parse & Save Lesson').item.json;
const phases = [
  { id: 'phase_0a', name: 'Theme Preview',      game_refs: [] },
  { id: 'phase_0b', name: 'Flash Cards',         game_refs: [] },
  { id: 'phase_1',  name: 'Memory Sprint',       game_refs: [] },
  { id: 'phase_2',  name: 'Story Mode',          game_refs: [] },
  { id: 'phase_3',  name: 'Game Breaks',         game_refs: ['tile_match','codebreaker','tic_tac_toe'] },
  { id: 'phase_4',  name: 'Real-Life Challenge', game_refs: [] },
  { id: 'phase_5',  name: 'Consolidation',       game_refs: [] },
  { id: 'phase_6',  name: 'Final Boss',          game_refs: [] },
  { id: 'phase_7',  name: 'Reflection',          game_refs: [] }
];
return phases.map(p => ({ json: {
  task_id: task.task_id,
  lesson_id: task.lesson_id,
  subject: task.subject,
  grade: task.grade,
  lang: task.lang,
  lesson_path: task.lesson_path,
  phase_id: p.id,
  phase_name: p.name,
  game_refs: p.game_refs
} }));

const item = $input.item.json;
const fs = require('fs');

let basePrompt = 'You are a NETS homework phase generator.';
let unifiedSchema = '';
let subjectFramework = '';
let phaseSpec = '';
let outputSchema = '{}';
let gameContent = '';

try { basePrompt = fs.readFileSync('/home/node/nets/frameworks/system/phase_worker_base.md', 'utf8'); } catch(e) {}
try { unifiedSchema = fs.readFileSync('/home/node/nets/frameworks/unified/schema.md', 'utf8'); } catch(e) {}
try { subjectFramework = fs.readFileSync('/home/node/nets/frameworks/subjects/matematika.md', 'utf8'); } catch(e) {}
try { phaseSpec = fs.readFileSync(`/home/node/nets/frameworks/unified/${item.phase_id}.md`, 'utf8'); } catch(e) { phaseSpec = `Phase: ${item.phase_id}`; }
try { outputSchema = fs.readFileSync(`/home/node/nets/frameworks/schemas/${item.phase_id}.json`, 'utf8'); } catch(e) {}

let lessonJson = '{}';
try { lessonJson = fs.readFileSync(item.lesson_path, 'utf8'); } catch(e) {}

if (item.game_refs && item.game_refs.length > 0) {
  item.game_refs.forEach(g => {
    try { gameContent += fs.readFileSync(`/home/node/nets/frameworks/games/${g}.md`, 'utf8') + '\n\n'; } catch(e) {}
  });
}

const systemMessage = [
  '## LAYER 1: SYSTEM INVARIANTS\n' + basePrompt,
  unifiedSchema ? ('## LAYER 2: UNIFIED FRAMEWORK SCHEMA\n' + unifiedSchema) : '',
  subjectFramework ? ('## LAYER 3: SUBJECT FRAMEWORK\n' + subjectFramework) : '',
  phaseSpec ? ('## LAYER 4: PHASE SPECIFICATION\n' + phaseSpec) : '',
  gameContent ? ('## LAYER 5: GAME MECHANICS\n' + gameContent) : ''
].filter(Boolean).join('\n\n---\n\n');

const userMessage = [
  `## LAYER 6: LESSON CONTENT\n${lessonJson}`,
  `## LAYER 7: TASK CONTEXT\n{"grade": ${item.grade}, "lang": "${item.lang}", "subject": "${item.subject}", "lesson_id": "${item.lesson_id}", "phase_id": "${item.phase_id}"}`,
  `## LAYER 8: TASK\nProduce the ${item.phase_name} phase deliverable. Return ONLY valid JSON matching this schema exactly:\n${outputSchema}`
].join('\n\n---\n\n');

const payload = {
  model: 'kimi-k2.5',
  messages: [
    { role: 'system', content: systemMessage },
    { role: 'user', content: userMessage }
  ],
  response_format: { type: 'json_object' },
  temperature: 1,
  max_tokens: 16000
};

return [{ json: { payload, task_id: item.task_id, lesson_id: item.lesson_id, phase_id: item.phase_id, phase_name: item.phase_name, subject: item.subject, grade: item.grade, lang: item.lang, lesson_path: item.lesson_path, call_start: Date.now() } }];

const response = $json;
const meta = $('Compose Phase Prompt').item.json;

let phaseJson;
try {
  let raw = response.choices[0].message.content || '';
  raw = raw.replace(/^\s*```json\s*/i, '').replace(/^\s*```\s*/i, '').replace(/\s*```\s*$/i, '').trim();
  if (!raw) throw new Error('empty response from model');
  phaseJson = JSON.parse(raw);
} catch(e) {
  throw new Error(`Phase ${meta.phase_id} invalid JSON: ` + e.message);
}

const tokensIn = response.usage?.prompt_tokens || 0;
const tokensOut = response.usage?.completion_tokens || 0;
const costUsd = (tokensIn * 0.60 + tokensOut * 2.50) / 1000000;
const latency = Date.now() - meta.call_start;
const phaseJsonStr = JSON.stringify(phaseJson).replace(/'/g, "''");

return [{ json: {
  phase_output_json: phaseJsonStr,
  task_id: meta.task_id,
  lesson_id: meta.lesson_id,
  phase_id: meta.phase_id,
  subject: meta.subject,
  grade: meta.grade,
  lang: meta.lang,
  lesson_path: meta.lesson_path,
  tokens_in: tokensIn,
  tokens_out: tokensOut,
  cost_usd: costUsd,
  latency_ms: latency
}}];

const allRows = $input.all();
if (allRows.length === 0) throw new Error('No phase outputs found in DB');

const task_id = allRows[0].json.task_id;
const lesson_id = allRows[0].json.lesson_id;

const phases = {};
allRows.forEach(row => { phases[row.json.phase_id] = row.json.output_json; });

const p0a = phases.phase_0a || {};
const p0b = phases.phase_0b || {};
const p1  = phases.phase_1  || {};
const p2  = phases.phase_2  || {};
const p3  = phases.phase_3  || {};
const p4  = phases.phase_4  || {};
const p5  = phases.phase_5  || {};
const p6  = phases.phase_6  || {};
const p7  = phases.phase_7  || {};

let md = [];
md.push(`# NETS Uy Vazifasi — Matematika, ${lesson_id}`);
md.push('');

md.push('---\n## PHASE 0-A: MAVZU KO\'RIGI');
if (p0a.gate_quote) { md.push(`> *"${p0a.gate_quote.text}"* — ${p0a.gate_quote.author}`); md.push(''); }
(p0a.panels || []).forEach(p => { md.push(`### Panel ${p.panel_number}: ${p.title}`); md.push(p.content || ''); md.push(''); });
if (p0a.bost_goal) md.push(`**Bugungi Maqsad:** ${p0a.bost_goal}\n`);

md.push('---\n## PHASE 0-B: FLASH KARTALAR');
(p0b.cards || []).forEach(c => { md.push(`- **${c.front_text}** → ${c.back_text}`); });
md.push('');

md.push('---\n## PHASE 1: XOTIRA SPRINTI');
(p1.items || []).forEach(item => {
  md.push(`${item.item_number}. ${item.question_text}`);
  if (item.options) item.options.forEach((o, i) => md.push(`   ${String.fromCharCode(65+i)}) ${o}`));
  md.push(`   **Javob:** ${item.correct_answer}`);
  md.push('');
});

md.push('---\n## PHASE 2: HIKOYA REJIMI');
(p2.segments || []).forEach(seg => {
  md.push(seg.narrative_text || '');
  md.push('');
  if (seg.checkpoint) {
    const cp = seg.checkpoint;
    md.push(`**Savol:** ${cp.question}`);
    if (cp.options) cp.options.forEach((o,i) => md.push(`${String.fromCharCode(65+i)}) ${o}`));
    md.push(`**Javob:** ${cp.correct_answer}`);
    if (cp.explanation) md.push(`*${cp.explanation}*`);
    md.push('');
  }
});

md.push('---\n## PHASE 3: O\'YIN TANAFFUSLARI');
(p3.games || []).forEach(game => {
  md.push(`### ${game.slot}-o'yin: ${game.game_name}`);
  (game.items || []).forEach(item => {
    if (item.question_or_prompt) md.push(`${item.item_number}. ${item.question_or_prompt}`);
    else if (item.left_item) md.push(`${item.pair_number}. ${item.left_item} — ${item.right_item}`);
    if (item.correct_answer) md.push(`   **Javob:** ${item.correct_answer}`);
    md.push('');
  });
});

md.push('---\n## PHASE 4: HAYOTIY VAZIFA');
if (p4.scenario_text) md.push(p4.scenario_text + '\n');
(p4.questions || []).forEach(q => {
  md.push(`${q.question_number}. ${q.question_text}`);
  md.push(`   **Javob:** ${q.correct_answer}`);
  md.push('');
});

md.push('---\n## PHASE 5: MUSTAHKAMLASH');
if (p5.technique_chosen) md.push(`**Usul:** ${p5.technique_chosen}`);
if (p5.mnemonic_exercise) md.push(p5.mnemonic_exercise);
md.push('');

md.push('---\n## PHASE 6: YAKUNIY BOSS');
(p6.questions || []).forEach(q => {
  md.push(`${q.question_number}. [${(q.difficulty||'').toUpperCase()} | ${q.damage_hp} HP] ${q.question_text}`);
  if (q.hint_text) md.push(`   *Yordam: ${q.hint_text}*`);
  md.push(`   **Javob:** ${q.correct_answer}`);
  md.push('');
});

md.push('---\n## PHASE 7: FIKRLASH');
if (p7.session_summary) { p7.session_summary.forEach(s => md.push(`- ${s}`)); md.push(''); }
(p7.reflection_prompts || []).forEach(p => { const t = typeof p === 'string' ? p : p.prompt_text; md.push(`• ${t}`); });
if (p7.spaced_rep_schedule) { const s = p7.spaced_rep_schedule; md.push(`\n**Qayta ko'rish:** ${s.day1} → ${s.day3} → ${s.day7} → ${s.day21}`); }

const fs = require('fs');
const mdPath = `/home/node/nets/nets-output/${lesson_id}_homework.md`;
fs.writeFileSync(mdPath, md.join('\n'));

return [{ json: { md_path: mdPath, task_id, lesson_id } }];
